 10	export interface GraphHelpFindProps {
 11	  children: React.ReactNode;
 12	  className?: string;
 13	  onClose: () => void;
 14	}
 15	
 16	const height = 'auto';
 17	const maxHeight = '34rem';
 18	const maxWidth = '37rem';
 19	const width = maxWidth;
 20	const contentWidth = '34.5rem';
 21	
 22	const tabFont: React.CSSProperties = {
 23	  fontSize: 'var(--kiali-global--font-size)'
 24	};
 25	
 26	const popoverStyle = kialiStyle({
 27	  height: height,
 28	  maxHeight: maxHeight,
 29	  maxWidth: maxWidth,
 30	  overflow: 'hidden',
 31	  overflowX: 'auto',
 32	  overflowY: 'auto',
 33	  width: width
 34	});
 35	
 36	const prefaceStyle = kialiStyle({
 37	  fontSize: '0.75rem',
 38	  color: PFColors.ColorLight100,
 39	  backgroundColor: PFColors.Blue600,
 40	  width: contentWidth,
 41	  height: '4rem',
 42	  padding: '0.25rem',
 43	  resize: 'none',
 44	  overflowY: 'hidden'
 45	});
 46	
 47	export const GraphHelpFind: React.FC<GraphHelpFindProps> = (props: GraphHelpFindProps) => {
 48	  // Incrementing mock counter to force a re-render in React hooks
 49	  const [, forceUpdate] = React.useReducer(x => x + 1, 0);
 50	
 51	  const onResize = (): void => {
 52	    forceUpdate();
 53	  };
 54	
 55	  const preface =
 56	    'You can use the Find and Hide fields to highlight or hide graph edges and nodes. Each field accepts ' +
 57	    'expressions using the language described below. Preset expressions are available via the dropdown. ' +
 58	    'Hide takes precedence when using Find and Hide together. ';
 59	
 60	  const edgeColumns: ThProps[] = [{ title: 'Expression' }, { title: 'Notes' }];
 61	
 62	  const edgeRows: IRow[] = [
 63	    { cells: ['destprincipal <op> <principal>'] },
 64	    { cells: ['grpc <op> <number>', 'unit: requests per second'] },
 65	    { cells: ['%grpcerr <op> <number>', 'range: [0..100]'] },
 66	    { cells: ['%grpctraffic <op> <number>', 'range: [0..100]'] },
 67	    { cells: ['http <op> <number>', 'unit: requests per second'] },
 68	    { cells: ['%httperr <op> <number>', 'range: [0..100]'] },
 69	    { cells: ['%httptraffic <op> <number>', 'range: [0..100]'] },
 70	    { cells: ['mtls', `will auto-enable 'security' display option`] },
 71	    { cells: ['protocol <op> <protocol>', 'grpc, http, tcp, etc..'] },
 72	    { cells: ['responsetime <op> <number>', `unit: millis, will auto-enable 'P95 response time' edge labels`] },
 73	    { cells: ['sourceprincipal <op> <principal>'] },
 74	    { cells: ['tcp <op> <number>', 'unit: bytes per second'] },
 75	    {
 76	      cells: ['throughput <op> <number>', `unit: bytes per second, will auto-enable 'request throughput' edge labels`]
 77	    },
 78	    { cells: ['traffic', 'any traffic for any protocol'] }
 79	  ];
 80	
 81	  const exampleColumns: ThProps[] = [{ title: 'Expression' }, { title: 'Description' }];
 82	
 83	  const exampleRows: IRow[] = [
 84	    {
 85	      cells: [
 86	        'label:region',
 87	        `nodes with the 'region' label. This tests for label existence, the label value is ignored.`
 88	      ]
 89	    },
 90	    {
 91	      cells: [
 92	        '!label:region',
 93	        `nodes without the 'region' label. This tests for label existence, the label value is ignored.`
 94	      ]
 95	    },
 96	    { cells: ['label:region = east', `nodes with 'region' label equal to 'east'`] },
 97	    {
 98	      cells: [
 99	        'label:region != east',
100	        `nodes with 'region' label not equal to 'east'.  Note, "!label:region = east" is invalid, leading negation is valid only for label existence.`
101	      ]
102	    },
103	    { cells: ['name = reviews', `nodes with app or service name or workload name equal to 'reviews'`] },
104	    { cells: ['name not contains rev', `"nodes with app, service name and workload name not containing 'rev'`] },
105	    { cells: ['app startswith product', `nodes with app starting with 'product'`] },
106	    {
107	      cells: ['app != details and version=v1', `nodes with app not equal to 'details' and with version equal to 'v1'`]
108	    },
109	    { cells: ['!outofmesh', `nodes out of mesh (With no sidecar and no Istio Ambient components)`] },
110	    { cells: ['httpin > 0.5', `nodes with inbound http rate > 0.5 rps`] },
111	    { cells: ['tcpout >= 1000', `nodes with outbound tcp rates >= 1000 bps`] },
112	    { cells: ['!traffic', 'edges with no traffic'] },
113	    { cells: ['http > 0.5', `edges with http rate > 0.5 rps`] },
114	    { cells: ['rt > 500', `edges with response time > 500ms. (requires response time edge labels)`] },
115	    { cells: ['%httptraffic >= 50.0', `edges with >= 50% of the outbound http request traffic of the parent`] },
116	    {
117	      cells: [
118	        'node = svc and svc startswith det or !traffic',
119	        'service node starting with "det" or edges with no traffic'
120	      ]
121	    },
122	    { cells: ['rank <= 2', 'nodes with a top 2 ranking'] }
123	  ];
124	
125	  const nodeColumns: ThProps[] = [{ title: 'Expression' }, { title: 'Notes' }];
126	
127	  const nodeRows: IRow[] = [
128	    { cells: ['app <op> <appName>', 'tests against canonical service'] },
129	    { cells: ['cluster <op> <clusterName>'] },
130	    { cells: ['grpcin <op> <number>', 'unit: requests per second'] },
131	    { cells: ['grpcout <op> <number>', 'unit: requests per second'] },
132	    { cells: ['httpin <op> <number>', 'unit: requests per second'] },
133	    { cells: ['httpout <op> <number>', 'unit: requests per second'] },
134	    { cells: ['label:<label> <op> <value>', '<label> is a k8s label on the service, workload, etc'] },
135	    { cells: ['name <op> <string>', 'tests against canonical service, operation, service and workload names'] },
136	    { cells: ['namespace <op> <namespaceName>'] },
137	    { cells: ['node <op> <nodeType>', 'nodeType: app | operation | service | workload | unknown'] },
138	    { cells: ['operation <op> <operationName>'] },
139	    { cells: ['rank <op> <number>', 'unit: 1..100'] },
140	    { cells: ['service <op> <serviceName>'] },
141	    { cells: ['version <op> <string>', 'tests against canonical revision'] },
142	    { cells: ['tcpin <op> <number>', 'unit: bytes per second'] },
143	    { cells: ['tcpout <op> <number>', 'unit: bytes per second'] },
144	    { cells: ['workload <op> <workloadName>'] },
145	    { cells: ['circuitbreaker'] },
146	    { cells: ['faultinjection'] },
147	    { cells: ['healthy', 'is not degraded or failing.'] },
148	    { cells: ['idle', `will auto-enable 'idle nodes' display option`] },
149	    { cells: ['mirroring'] },
150	    { cells: ['outside', 'is outside of requested namespaces'] },
151	    { cells: ['requestrouting'] },
152	    { cells: ['requesttimeout'] },
153	    { cells: ['outofmesh'] },
154	    { cells: ['serviceentry'] },
155	    { cells: ['tcptrafficshifting'] },
156	    { cells: ['trafficshifting'] },
157	    { cells: ['trafficsource', `has only outbound edges`] },
158	    { cells: ['virtualservice'] },
159	    { cells: ['workloadentry'] }
160	  ];
161	
162	  const noteColumns: ThProps[] = [{ title: 'Usage Note', width: 10 }];
163	
164	  const noteRows: IRow[] = [
165	    { cells: ['Press Tab key to autocomplete operands.'] },
166	    { cells: ['OR has precedence over AND.  Parentheses are not supported.'] },
167	    { cells: ['Use OR to combine node and edge criteria.'] },
168	    { cells: ['Use "<operand> = NaN" to test for no activity. Use "!= NaN" for any activity. (e.g. httpout = NaN)'] },
169	    { cells: [`Unary operands may optionally be prefixed with "is" or "has". (i.e. "has mtls")`] },
170	    { cells: ['The "name" operand expands internally to an "OR" expression (an "AND" when negated).'] },
171	    {
172	      cells: [
173	        'For the configured app and version labels, use the "app" and "version" Node operands, as opposed to "label:".'
174	      ]
175	    },
176	    { cells: ['Abbreviate: ns|namespace, svc|service, se|serviceentry, wl|workload, we|workloadentry, op|operation'] },
177	    { cells: ['Abbreviate: rt|responsetime, om|outofmesh, vs|virtualservice'] },
178	    {
179	      cells: [
180	        'Abbreviate: cb|circuitbreaker, fi|faultinjection, rr|requestrouting, rto|requesttimeout, ts|trafficshifting'
181	      ]
182	    },
183	    { cells: ['Hiding nodes will automatically hide connected edges.'] },
184	    { cells: ['Hiding edges will automatically hide nodes left with no visible edges.'] },
185	    { cells: ['Hiding "healthy" nodes may still leave valid, healthy edges in the graph.'] }
186	  ];
187	
188	  const operatorColumns: ThProps[] = [{ title: 'Operator' }, { title: 'Description' }];
189	
190	  const operatorRows: IRow[] = [
191	    { cells: ['! | not <unary expression>', `negation`] },
192	    { cells: ['=', `equals`] },
193	    { cells: ['!=', `not equals`] },
194	    { cells: ['endswith | $=', `ends with, strings only`] },
195	    { cells: ['!endswith | !$=', `not ends with, strings only`] },
196	    { cells: ['startswith | ^=', `starts with, strings only`] },
197	    { cells: ['!startswith | !^=', `not starts with, strings only`] },
198	    { cells: ['contains | *=', 'contains, strings only'] },
199	    { cells: ['!contains | !*=', 'not contains, strings only'] },
