208	  };
209	
210	  const exampleTable = getTable('Example Table', exampleColumns, exampleRows);
211	  const nodeTable = getTable('Node Table', nodeColumns, nodeRows);
212	  const edgeTable = getTable('Edge Table', edgeColumns, edgeRows);
213	  const operatorTable = getTable('Operator Table', operatorColumns, operatorRows);
214	  const noteTable = getTable('Note Table', noteColumns, noteRows);
215	
216	  return (
217	    <>
218	      <ReactResizeDetector
219	        refreshMode="debounce"
220	        refreshRate={100}
221	        skipOnMount={true}
222	        handleWidth={true}
223	        handleHeight={true}
224	        onResize={onResize}
225	      />
226	
227	      <Popover
228	        data-test="graph-find-hide-help"
229	        className={popoverStyle}
230	        position={PopoverPosition.auto}
231	        isVisible={true}
232	        hideOnOutsideClick={false}
233	        shouldClose={props.onClose}
234	        headerContent={
235	          <div>
236	            <span>Graph Find/Hide</span>
237	          </div>
238	        }
239	        bodyContent={
240	          <>
241	            <textarea className={`${prefaceStyle}`} readOnly={true} value={preface} />
242	
243	            <SimpleTabs id="graph_find_help_tabs" defaultTab={0} style={{ width: contentWidth }}>
244	              <Tab style={tabFont} eventKey={0} title="Examples">
245	                {exampleTable}
246	              </Tab>
247	
248	              <Tab style={tabFont} eventKey={1} title="Nodes">
249	                {nodeTable}
250	              </Tab>
251	
252	              <Tab style={tabFont} eventKey={2} title="Edges">
253	                {edgeTable}
254	              </Tab>
255	
256	              <Tab style={tabFont} eventKey={3} title="Operators">
257	                {operatorTable}
258	              </Tab>
259	
260	              <Tab style={tabFont} eventKey={4} title="Usage Notes">
261	                {noteTable}
262	              </Tab>
263	            </SimpleTabs>
264	          </>
265	        }
266	      >
267	        <>{props.children}</>
268	      </Popover>
269	    </>
270	  );
271	};

